        return docker_path

    # 2. Local development path (relative to this file)
    local_path = Path(__file__).resolve().parent.parent.parent.parent / "config"
    if local_path.exists():
        return local_path

    # 3. Current working directory + config
    cwd_path = Path.cwd() / "config"
    if cwd_path.exists():
        return cwd_path

